function hexToRgb(hex) {
  return [parseInt(hex.slice(1,3),16), parseInt(hex.slice(3,5),16), parseInt(hex.slice(5,7),16)];
}

function rgbToHex(r,g,b) {
  return "#" + [r,g,b].map(v => v.toString(16).padStart(2,"0")).join("");
}

/* Scanline flood fill — fast and stack-safe.
   Fills enclosed white regions, stopping at dark line-art boundaries.
   Aborts early if fill exceeds maxPixels (background protection). */
function floodFill(colorData, lineData, w, h, sx, sy, rgb, threshold) {
  sx = Math.round(sx); sy = Math.round(sy);
  if (sx < 0 || sx >= w || sy < 0 || sy >= h) return 0;

  const cd = colorData.data;
  const ld = lineData.data;
  const idx = (x,y) => (y * w + x) * 4;
  const maxPixels = w * h * MAX_FILL_RATIO;

  // Check if start is on a boundary
  const si = idx(sx, sy);
  if ((ld[si] + ld[si+1] + ld[si+2]) / 3 < threshold) return 0;

  const visited = new Uint8Array(w * h);
  const stack = [sx, sy];
  let filled = 0;

  while (stack.length > 0) {
    const y = stack.pop();
    const x = stack.pop();
    if (x < 0 || x >= w || y < 0 || y >= h) continue;
    const vi = y * w + x;
    if (visited[vi]) continue;
    visited[vi] = 1;

    const i = idx(x, y);
    const brightness = (ld[i] + ld[i+1] + ld[i+2]) / 3;
    if (brightness < threshold) continue;

    cd[i] = rgb[0]; cd[i+1] = rgb[1]; cd[i+2] = rgb[2]; cd[i+3] = 255;
    filled++;

    // Early abort — this region is too large (background)
    if (filled > maxPixels) return filled;

    if (x+1 < w  && !visited[vi+1])     stack.push(x+1, y);
    if (x-1 >= 0 && !visited[vi-1])     stack.push(x-1, y);
    if (y+1 < h  && !visited[vi+w])     stack.push(x, y+1);
    if (y-1 >= 0 && !visited[vi-w])     stack.push(x, y-1);
  }
  return filled;
}

function Swatch({ color, name, selected, onClick }) {
  return (
    <button onClick={onClick} title={name} style={{
      width: 28, height: 28, borderRadius: "50%",
      border: selected ? "3px solid #2c2c2c" : "2px solid #ccc",
      backgroundColor: color, cursor: "pointer", transition: "all .15s",
      boxShadow: selected ? "0 0 0 2px #fff, 0 0 0 4px #2c2c2c" : "0 1px 3px rgba(0,0,0,.1)",
      transform: selected ? "scale(1.15)" : "scale(1)",
      padding: 0, outline: "none", flexShrink: 0,
    }} />
  );
}

